document.querySelectorAll('[data-palette]').forEach(grid => {
  const palette = grid.dataset.palette;
  const colors = PALETTES[palette] || [];
  colors.forEach(([name, hex]) => {
    const el = document.createElement('div');
    el.className = 'ds__color';
    el.innerHTML = `
      <div class="ds__color-swatch" style="background:var(${name})"></div>
      <div class="ds__color-info">
        <div class="ds__color-name">${name.replace('--color-', '')}</div>
        <div class="ds__color-hex">${hex}</div>
      </div>
    `;
    grid.appendChild(el);
  });
});

/* ── Type scale ──────────────────────────────────────── */
const TYPE_SCALE = [
  ['2xs', '8px', 10],
  ['xs', '10px', 12],
  ['sm', '12px', 14],
  ['md', '14px', 18],
  ['lg', '16px', 20],
  ['xl', '18px', 22],
  ['2xl', '20px', 26],
  ['3xl', '24px', 32],
];
const typeScaleEl = document.getElementById('typeScale');
TYPE_SCALE.forEach(([alias, size, lh]) => {
  const row = document.createElement('div');
  row.className = 'ds__type-row';
  row.innerHTML = `
    <span class="ds__type-label">--font-size-${alias}<br><span style="color:var(--color-gray-500)">${size} / lh ${lh}px</span></span>
    <span class="ds__type-sample" style="font-size:${size};line-height:${lh}px">The quick brown fox jumps over the lazy dog</span>
  `;
  typeScaleEl.appendChild(row);
});

/* ── Spacing scale ───────────────────────────────────── */
const SPACING = [
  ['--space-1', '4px', 4],
  ['--space-2', '8px', 8],
  ['--space-3', '12px', 12],
  ['--space-4', '16px', 16],
  ['--space-6', '24px', 24],
];
const spacingEl = document.getElementById('spacingScale');
SPACING.forEach(([name, value, px]) => {
  const row = document.createElement('div');
  row.className = 'ds__space-row';
  row.innerHTML = `
    <span class="ds__space-label">${name}</span>
    <span class="ds__space-value">${value}</span>
    <span class="ds__space-bar" style="width:${px}px"></span>
  `;
  spacingEl.appendChild(row);
});

/* ── Component preview/code tabs ─────────────────────── */
document.querySelectorAll('[data-component]').forEach(comp => {
  const tabs = comp.querySelectorAll('.ds__tab');
  const preview = comp.querySelector('[data-preview]');
  const code = comp.querySelector('[data-code]');
  tabs.forEach(tab => {
    tab.addEventListener('click', () => {
      tabs.forEach(t => t.classList.remove('is-active'));
      tab.classList.add('is-active');
      const target = tab.dataset.tab;
      if (target === 'preview') {
        preview.style.display = '';
        code.classList.remove('is-visible');
      } else {
        preview.style.display = 'none';
        code.classList.add('is-visible');
      }
    });
  });
});

/* ── Copy button ─────────────────────────────────────── */
document.querySelectorAll('.ds__copy-btn').forEach(btn => {
  btn.addEventListener('click', async () => {
    const code = btn.parentElement.querySelector('code').textContent;
    try {
      await navigator.clipboard.writeText(code);
      btn.classList.add('is-copied');
      btn.innerHTML = '<span class="material-icons-outlined" style="font-size:14px">check</span>Copiado';
      setTimeout(() => {
        btn.classList.remove('is-copied');
        btn.innerHTML = '<span class="material-icons-outlined" style="font-size:14px">content_copy</span>Copiar';
      }, 2000);
    } catch (e) {
      console.error('Falha ao copiar:', e);
    }
  });
});

/* ── Active nav link on scroll ───────────────────────── */
const navLinks = document.querySelectorAll('.ds__nav-link');
const sections = document.querySelectorAll('.ds__section');

const observer = new IntersectionObserver((entries) => {
  entries.forEach(entry => {
    if (entry.isIntersecting) {
      const id = entry.target.id;
      navLinks.forEach(l => l.classList.toggle('is-active', l.getAttribute('href') === '#' + id));
    }
  });
}, { rootMargin: '-30% 0px -60% 0px' });

sections.forEach(s => observer.observe(s));

/* ── Modal demo ───────────────────────────────────────── */
(function () {
  const modal = document.getElementById('modalDemo');
  const box = document.getElementById('modalDemoBox');
  if (!modal || !box) return;

  const open = (size) => {
    box.classList.remove('modal--small', 'modal--large');
    if (size) box.classList.add('modal--' + size);
    modal.classList.add('is-open');
  };
  const close = () => modal.classList.remove('is-open');

  document.getElementById('modalDemoOpen')?.addEventListener('click', () => open());
  document.getElementById('modalDemoOpenLarge')?.addEventListener('click', () => open('large'));
  document.getElementById('modalDemoOpenSmall')?.addEventListener('click', () => open('small'));

  modal.querySelectorAll('[data-modal-close]').forEach(btn => btn.addEventListener('click', close));
  modal.addEventListener('click', (e) => { if (e.target === modal) close(); });
  document.addEventListener('keydown', (e) => {
    if (e.key === 'Escape' && modal.classList.contains('is-open')) close();
  });
})();

/* ── Context Menu demo ────────────────────────────────── */
(function () {
  const trigger = document.getElementById('ctxMenuTrigger');
  const menu = document.getElementById('ctxMenuDemo');
  if (!trigger || !menu) return;

  trigger.addEventListener('click', (e) => {
    e.stopPropagation();
    menu.classList.toggle('is-open');
  });
  menu.querySelectorAll('.context-menu__item').forEach(item => {
    item.addEventListener('click', () => menu.classList.remove('is-open'));
  });
  document.addEventListener('click', (e) => {
    if (!e.target.closest('#ctxMenuDemo, #ctxMenuTrigger')) menu.classList.remove('is-open');
  });
  document.addEventListener('keydown', (e) => {
    if (e.key === 'Escape') menu.classList.remove('is-open');
  });
})();

/* ── Searchbar: has-value automatico + clear ─────────── */
document.querySelectorAll('.searchbar').forEach(sb => {
  if (sb.id === 'dsSearch') return; // o do sidebar tem handler próprio
  const input = sb.querySelector('.searchbar__input');
  const clear = sb.querySelector('.searchbar__clear');
  if (!input) return;

  // Estado inicial baseado em valor existente
  if (input.value.length > 0) sb.classList.add('has-value');

  input.addEventListener('input', () => {
    sb.classList.toggle('has-value', input.value.length > 0);
  });

  if (clear) {
    clear.addEventListener('click', (e) => {
      e.stopPropagation();
      input.value = '';
      sb.classList.remove('has-value');
      input.focus();
    });
  }
});

/* ── Filtro chips: trigger abre/fecha dropdown ────────── */
document.querySelectorAll('.filtro-chip[data-filtro]').forEach(chip => {
  const wrapper = chip.closest('.filtro-chip-wrapper');
  if (!wrapper) return;
  const dropdown = wrapper.querySelector('.filtro-dropdown');
  if (!dropdown) return;

  chip.addEventListener('click', (e) => {
    e.stopPropagation();
    const willOpen = !dropdown.classList.contains('is-open');
    document.querySelectorAll('.filtro-dropdown.is-open').forEach(d => d.classList.remove('is-open'));
    document.querySelectorAll('.filtro-chip[aria-expanded="true"]').forEach(c => c.setAttribute('aria-expanded', 'false'));
    if (willOpen) {
      dropdown.classList.add('is-open');
      chip.setAttribute('aria-expanded', 'true');
      dropdown.querySelector('.filtro-dropdown__search-input')?.focus();
    }
  });
});

document.addEventListener('click', (e) => {
  if (!e.target.closest('.filtro-chip-wrapper, .filtro-dropdown')) {
    document.querySelectorAll('.filtro-dropdown.is-open').forEach(d => {
      if (!d.closest('[data-preview]')) d.classList.remove('is-open');
    });
    document.querySelectorAll('.filtro-chip[aria-expanded="true"]').forEach(c => {
      if (!c.closest('[data-preview]')) c.setAttribute('aria-expanded', 'false');
    });
  }
});

/* ── Filtro dropdown: search filtra itens ─────────────── */
document.querySelectorAll('.filtro-dropdown__search-input').forEach(input => {
  input.addEventListener('input', (e) => {
    const term = e.target.value.toLowerCase();
    const list = e.target.closest('.filtro-dropdown')?.querySelector('.filtro-dropdown__list');
    if (!list) return;
    list.querySelectorAll('.filtro-dropdown__item').forEach(item => {
      item.style.display = item.textContent.toLowerCase().includes(term) ? '' : 'none';
    });
  });
});

/* ── Filtro dropdown: grupos colapsaveis ──────────────── */
document.querySelectorAll('.filtro-dropdown__group-header').forEach(header => {
  header.addEventListener('click', () => header.classList.toggle('is-collapsed'));
});

/* ── Composed buttons drop + Aplicar preço drop ───────── */
document.querySelectorAll('.composed-btn__drop, .aplicar-btn__drop').forEach(drop => {
  drop.addEventListener('click', (e) => {
    e.stopPropagation();
    const dropdownId = drop.dataset.dropdown;
    const dropdown = dropdownId ? document.getElementById(dropdownId) : drop.parentElement?.querySelector('.composed-dropdown');
    if (!dropdown) return;
    document.querySelectorAll('.composed-dropdown.is-open').forEach(d => {
      if (d !== dropdown) d.classList.remove('is-open');
    });
    dropdown.classList.toggle('is-open');
  });
});

document.addEventListener('click', (e) => {
  if (!e.target.closest('.composed-btn, .aplicar-btn, .composed-dropdown')) {
    document.querySelectorAll('.composed-dropdown.is-open').forEach(d => {
      if (!d.closest('[data-preview]')) d.classList.remove('is-open');
    });
  }
});

/* ── Composed btn solo: toggle is-selected ────────────── */
document.querySelectorAll('.composed-btn--solo').forEach(btn => {
  btn.addEventListener('click', () => btn.classList.toggle('is-selected'));
});

/* ── Title-btn dropdown trigger ───────────────────────── */
document.querySelectorAll('.title-btn').forEach(btn => {
  const wrapper = btn.closest('.title-btn-wrapper');
  if (!wrapper) return;
  const dropdown = wrapper.querySelector('.title-dropdown');
  if (!dropdown) return;

  btn.addEventListener('click', (e) => {
    e.stopPropagation();
    const willOpen = !dropdown.classList.contains('is-open');
    document.querySelectorAll('.title-dropdown.is-open').forEach(d => d.classList.remove('is-open'));
    document.querySelectorAll('.title-btn[aria-expanded="true"]').forEach(b => b.setAttribute('aria-expanded', 'false'));
    if (willOpen) {
      dropdown.classList.add('is-open');
      btn.setAttribute('aria-expanded', 'true');
    }
  });
});

document.querySelectorAll('.title-dropdown__item').forEach(item => {
  item.addEventListener('click', () => {
    const dd = item.closest('.title-dropdown');
    dd?.querySelectorAll('.title-dropdown__item--active').forEach(i => i.classList.remove('title-dropdown__item--active'));
    item.classList.add('title-dropdown__item--active');
    dd?.classList.remove('is-open');
  });
});

document.addEventListener('click', (e) => {
  if (!e.target.closest('.title-btn-wrapper, .title-dropdown')) {
    document.querySelectorAll('.title-dropdown.is-open').forEach(d => {
      if (!d.closest('[data-preview]')) d.classList.remove('is-open');
    });
  }
});

/* ── DatePicker: click no dia seleciona ───────────────── */
document.querySelectorAll('.date-picker').forEach(picker => {
  // Detecta se e range picker (tem dias com --in-range)
  const isRange = !!picker.querySelector('.date-picker__day--in-range');
  if (isRange) return; // mantem visual estatico para exemplo de range

  const days = picker.querySelectorAll('.date-picker__day:not(.date-picker__day--disabled)');
  days.forEach(day => {
    day.addEventListener('click', () => {
      days.forEach(d => d.classList.remove('date-picker__day--selected'));
      day.classList.add('date-picker__day--selected');
    });
  });
});

/* ── HourPicker: click na celula seleciona dentro da coluna ── */
document.querySelectorAll('.hour-picker__column').forEach(col => {
  const cells = col.querySelectorAll('.hour-picker__cell');
  cells.forEach(cell => {
    cell.addEventListener('click', () => {
      cells.forEach(c => c.classList.remove('is-selected'));
      cell.classList.add('is-selected');
      cell.scrollIntoView({ block: 'center', behavior: 'smooth' });
    });
  });
});

/* ── Grid pagination: click atualiza is-active ────────── */
