/* ── SelectPicker ─────────────────────────────────────── */
document.querySelectorAll('.select-picker').forEach(picker => {
  const trigger = picker.querySelector('.select-picker__trigger');
  const dropdown = picker.querySelector('.select-picker__dropdown');
  if (!trigger || !dropdown) return;

  trigger.addEventListener('click', (e) => {
    e.stopPropagation();
    const willOpen = !trigger.classList.contains('is-open');
    // Fecha todos os outros pickers primeiro
    document.querySelectorAll('.select-picker__trigger.is-open').forEach(t => {
      t.classList.remove('is-open');
      t.parentElement?.querySelector('.select-picker__dropdown')?.classList.remove('is-open');
    });
    if (willOpen) {
      trigger.classList.add('is-open');
      dropdown.classList.add('is-open');
      dropdown.querySelector('.select-picker__search-input')?.focus();
    }
  });

  // Seleção de item
  picker.querySelectorAll('.select-picker__item').forEach(item => {
    if (item.classList.contains('is-disabled')) return;
    item.addEventListener('click', () => {
      picker.querySelectorAll('.select-picker__item').forEach(i => i.classList.remove('is-selected'));
      item.classList.add('is-selected');

      // Atualiza label do trigger
      const placeholder = trigger.querySelector('.select-picker__placeholder');
      const label = placeholder || trigger.querySelector('span:not(.material-icons-outlined):not(.select-picker__chevron)');
      if (label) {
        label.textContent = item.textContent.trim();
        label.classList.remove('select-picker__placeholder');
      }
      trigger.classList.remove('is-open');
      dropdown.classList.remove('is-open');
    });
  });
});

// Click fora fecha qualquer SelectPicker aberto (excluindo demos estaticos em [data-preview])
document.addEventListener('click', (e) => {
  if (!e.target.closest('.select-picker')) {
    document.querySelectorAll('.select-picker__trigger.is-open').forEach(t => {
      if (!t.closest('[data-preview]')) t.classList.remove('is-open');
    });
    document.querySelectorAll('.select-picker__dropdown.is-open').forEach(d => {
      if (!d.closest('[data-preview]')) d.classList.remove('is-open');
    });
  }
});

/* ── Sub-row: toggle pelo price-menu e close button ──── */
document.querySelectorAll('[data-toggle-subrow]').forEach(btn => {
  const targetId = btn.dataset.toggleSubrow;
  const subRow = document.getElementById(targetId);
  if (!subRow) return;
  const headerRow = document.getElementById(targetId + '-header');

  function setVisible(visible) {
    const display = visible ? '' : 'none';
    subRow.style.display = display;
    if (headerRow) headerRow.style.display = display;
  }

  btn.addEventListener('click', () => {
    setVisible(subRow.style.display === 'none');
  });

  // O close button dentro da sub-row fecha (sub-row + header)
  subRow.querySelectorAll('.grid__sub-row__close').forEach(close => {
    close.addEventListener('click', () => setVisible(false));
  });
});

/* ── Radio: click no marcado desmarca ─────────────────── */
document.querySelectorAll('.radio').forEach(label => {
  const input = label.querySelector('.radio__input');
  if (!input) return;

  // Captura estado no mousedown (antes do navegador processar o click)
  label.addEventListener('mousedown', () => {
    label.dataset.wasChecked = input.checked ? '1' : '0';
  });

  // No click do label: se já estava marcado, prevent default e desmarca
  // preventDefault evita que o label re-ative (re-check) o input apos o click
  label.addEventListener('click', (e) => {
    if (label.dataset.wasChecked === '1') {
      e.preventDefault();
      input.checked = false;
      input.dispatchEvent(new Event('change', { bubbles: true }));
    }
    label.dataset.wasChecked = '';
  });

  // Acessibilidade: Space/Enter desmarca quando focado e já marcado
  input.addEventListener('keydown', (e) => {
    if ((e.key === ' ' || e.key === 'Enter') && input.checked) {
      e.preventDefault();
      input.checked = false;
      input.dispatchEvent(new Event('change', { bubbles: true }));
    }
  });
});

/* ── Switch interativo ──────────────────────────────── */
document.querySelectorAll('.switch').forEach(el => {
  const isDisabled = el.classList.contains('is-disabled') || el.getAttribute('aria-disabled') === 'true';

  // Acessibilidade: torna focavel via teclado e expoe estado para screen readers
  if (!isDisabled) {
    el.setAttribute('tabindex', '0');
    el.setAttribute('role', 'switch');
    el.setAttribute('aria-checked', el.classList.contains('is-checked') ? 'true' : 'false');
  }

  function toggle() {
    if (el.classList.contains('is-disabled')) return;
    // Half-state vira checked ao primeiro toggle (UX padrão)
    el.classList.remove('is-half');
    el.classList.toggle('is-checked');
    el.setAttribute('aria-checked', el.classList.contains('is-checked') ? 'true' : 'false');
  }

  el.addEventListener('click', (e) => {
    // Evita disparar duas vezes quando o click vem de um <input> aninhado
    if (e.target.tagName !== 'INPUT') toggle();
  });

  el.addEventListener('keydown', (e) => {
    if (e.key === ' ' || e.key === 'Enter') {
      e.preventDefault();
      toggle();
    }
  });
});

/* ── Resize do sidebar ──────────────────────────────── */
(function () {
  const root = document.documentElement;
  const handle = document.getElementById('dsNavResize');
  const STORAGE_KEY = 'ds__nav-width';
  const MIN = 200;
  const MAX = 480;
  const DEFAULT = 240;

  // Restaura valor salvo
  const saved = parseInt(localStorage.getItem(STORAGE_KEY), 10);
  if (Number.isFinite(saved) && saved >= MIN && saved <= MAX) {
    root.style.setProperty('--ds-nav-width', saved + 'px');
  }

  function clamp(v) { return Math.max(MIN, Math.min(MAX, v)); }

  function setWidth(px) {
    const v = clamp(Math.round(px));
    root.style.setProperty('--ds-nav-width', v + 'px');
    localStorage.setItem(STORAGE_KEY, String(v));
  }

  // Drag com mouse
  handle.addEventListener('mousedown', (e) => {
    e.preventDefault();
    handle.classList.add('is-active');
    document.body.classList.add('is-resizing-nav');

    function onMove(ev) { setWidth(ev.clientX); }
    function onUp() {
      handle.classList.remove('is-active');
      document.body.classList.remove('is-resizing-nav');
      document.removeEventListener('mousemove', onMove);
      document.removeEventListener('mouseup', onUp);
    }
    document.addEventListener('mousemove', onMove);
    document.addEventListener('mouseup', onUp);
  });

  // Duplo-clique reseta para o padrão
  handle.addEventListener('dblclick', () => setWidth(DEFAULT));

  // Acessibilidade: setas + Home/End com foco no handle
  handle.addEventListener('keydown', (e) => {
    const current = parseInt(getComputedStyle(root).getPropertyValue('--ds-nav-width'), 10) || DEFAULT;
    let next = current;
    if (e.key === 'ArrowLeft')  next = current - 16;
    if (e.key === 'ArrowRight') next = current + 16;
    if (e.key === 'Home')       next = MIN;
    if (e.key === 'End')        next = MAX;
    if (next !== current) {
      e.preventDefault();
      setWidth(next);
    }
  });
})();

/* ── Search no sidebar ──────────────────────────────── */
const dsSearch = document.getElementById('dsSearch');
const dsSearchInput = document.getElementById('dsSearchInput');
const dsSearchClear = document.getElementById('dsSearchClear');
const dsSearchEmpty = document.getElementById('dsSearchEmpty');

function escapeHtml(str) {
  return str.replace(/[&<>"']/g, c => ({
    '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;'
  }[c]));
}

function escapeRegex(str) {
  return str.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

// Snapshot do texto original de cada link e de cada título de seção (antes de qualquer highlight)
document.querySelectorAll('.ds__nav-link').forEach(link => {
  link.dataset.originalText = link.textContent;
});
document.querySelectorAll('.ds__nav-section-title').forEach(title => {
  title.dataset.originalText = title.textContent;
});

function filterDsNav(term) {
  const q = term.trim().toLowerCase();

  if (q === '') {
    // Reset: mostra tudo, restaura textos originais
    document.querySelectorAll('.ds__nav-link').forEach(link => {
      link.classList.remove('is-hidden');
      link.textContent = link.dataset.originalText;
    });
    document.querySelectorAll('.ds__nav-section-title').forEach(title => {
      title.textContent = title.dataset.originalText;
    });
    document.querySelectorAll('.ds__nav-section').forEach(s => s.classList.remove('is-hidden'));
    dsSearchEmpty.classList.remove('is-visible');
    dsSearch.classList.remove('has-value');
    return;
  }

  dsSearch.classList.add('has-value');
  let totalMatches = 0;
  const regex = new RegExp(escapeRegex(q), 'gi');

  document.querySelectorAll('.ds__nav-section').forEach(section => {
    const titleEl = section.querySelector('.ds__nav-section-title');
    const titleText = titleEl ? titleEl.dataset.originalText : '';
    const sectionTitleMatches = titleText.toLowerCase().includes(q);
    let sectionHasMatch = sectionTitleMatches;

    // Quando o título da seção casa, exibe a seção inteira (e destaca os links).
    // Caso contrario, filtra link a link como antes.
    section.querySelectorAll('.ds__nav-link').forEach(link => {
      const text = link.dataset.originalText;
      const linkMatches = text.toLowerCase().includes(q);
      const safe = escapeHtml(text);

      if (sectionTitleMatches) {
        link.classList.remove('is-hidden');
        // Se o link também casa, destaca; senão restaura texto puro
        link.innerHTML = linkMatches
          ? safe.replace(regex, m => '<span class="ds__nav-link__match">' + m + '</span>')
          : safe;
        totalMatches++;
      } else if (linkMatches) {
        link.classList.remove('is-hidden');
        link.innerHTML = safe.replace(regex, m => '<span class="ds__nav-link__match">' + m + '</span>');
        sectionHasMatch = true;
        totalMatches++;
      } else {
        link.classList.add('is-hidden');
        link.textContent = text;
      }
    });

    // Highlight no título da seção quando ele casa
    if (titleEl) {
      const safeTitle = escapeHtml(titleText);
      titleEl.innerHTML = sectionTitleMatches
        ? safeTitle.replace(regex, m => '<span class="ds__nav-link__match">' + m + '</span>')
        : safeTitle;
    }

    section.classList.toggle('is-hidden', !sectionHasMatch);
  });

  dsSearchEmpty.classList.toggle('is-visible', totalMatches === 0);
}

dsSearchInput.addEventListener('input', e => filterDsNav(e.target.value));

dsSearchClear.addEventListener('click', () => {
  dsSearchInput.value = '';
  filterDsNav('');
  dsSearchInput.focus();
});

// Atalho: tecla "/" foca o campo de busca (estilo GitHub)
document.addEventListener('keydown', e => {
  if (e.key === '/' && document.activeElement.tagName !== 'INPUT' && document.activeElement.tagName !== 'TEXTAREA') {
    e.preventDefault();
    dsSearchInput.focus();
  }
  if (e.key === 'Escape' && document.activeElement === dsSearchInput) {
    dsSearchInput.value = '';
    filterDsNav('');
    dsSearchInput.blur();
  }
});
